						</tr>
					</thead>
					<tbody>
						<?php foreach ($posts_data as $post_data):
							$is_draft    = ($post_data['post_status'] === 'draft');
							$is_partial  = $post_data['is_partial'];
							$is_publish  = ($post_data['post_status'] === 'publish');
						?>
						<tr data-post-id="<?php echo esc_attr($post_data['post_id']); ?>" data-history-id="<?php echo esc_attr($post_data['history_id']); ?>">
							<?php if ($post_status_filter === 'pending_review'): ?>
							<td>
								<label class="screen-reader-text" for="cb-select-<?php echo esc_attr($post_data['post_id']); ?>"><?php esc_html_e('Select Post', 'ai-post-scheduler'); ?></label>
								<input id="cb-select-<?php echo esc_attr($post_data['post_id']); ?>"
									type="checkbox"
									class="aips-post-checkbox"
									value="<?php echo esc_attr($post_data['post_id']); ?>"
									data-post-id="<?php echo esc_attr($post_data['post_id']); ?>"
									data-history-id="<?php echo esc_attr($post_data['history_id']); ?>">
							</td>
							<?php endif; ?>
							<td>
								<a href="<?php echo esc_url($post_data['edit_link']); ?>" class="cell-primary">
									<?php echo esc_html($post_data['title']); ?>
								</a>
							</td>
							<td>
								<?php if ($is_publish && !$is_partial): ?>
									<span class="aips-badge aips-badge-success"><?php esc_html_e('Published', 'ai-post-scheduler'); ?></span>
								<?php elseif ($is_draft): ?>
									<span class="aips-badge aips-badge-neutral"><?php esc_html_e('Pending Review', 'ai-post-scheduler'); ?></span>
								<?php else: ?>
									<span class="aips-badge aips-badge-neutral"><?php echo esc_html($controller->format_post_status($post_data['post_status'])); ?></span>
								<?php endif; ?>

								<?php if ($is_partial): ?>
									<?php if ($post_data['is_currently_incomplete'] && !empty($post_data['missing_components'])): ?>
										<?php foreach ($post_data['missing_components'] as $component_label): ?>
										<span class="aips-badge aips-badge-warning"><?php echo esc_html($component_label); ?></span>
										<?php endforeach; ?>
									<?php else: ?>
										<span class="aips-badge aips-badge-warning"><?php esc_html_e('Was Partial', 'ai-post-scheduler'); ?></span>
									<?php endif; ?>
								<?php endif; ?>
							</td>
							<td>
								<span class="aips-badge aips-badge-neutral">
									<?php echo esc_html($post_data['source']); ?>
								</span>
							</td>
							<td>
								<div class="cell-meta">
									<?php echo esc_html(date_i18n(get_option('date_format') . ' ' . get_option('time_format'), strtotime($post_data['date_generated']))); ?>
								</div>
							</td>
							<td>
								<div class="cell-meta">
									<?php echo esc_html(date_i18n(get_option('date_format') . ' ' . get_option('time_format'), strtotime($post_data['date_updated']))); ?>
								</div>
							</td>
							<td>
								<div class="cell-actions">
									<a href="<?php echo esc_url($post_data['edit_link']); ?>"
										class="aips-btn aips-btn-sm aips-btn-secondary"
										<?php if ($is_draft): ?>target="_blank"<?php endif; ?>
										title="<?php esc_attr_e('Edit this post', 'ai-post-scheduler'); ?>">
										<span class="dashicons dashicons-edit"></span>
										<?php esc_html_e('Edit', 'ai-post-scheduler'); ?>
									</a>

									<?php if ($is_draft): ?>
									<button type="button"
										class="aips-btn aips-btn-sm aips-btn-secondary aips-preview-post"
