						switch ($post_status_filter) {
							case 'published':
								esc_html_e('No Published Posts', 'ai-post-scheduler');
								break;
							case 'pending_review':
								esc_html_e('No Draft Posts', 'ai-post-scheduler');
								break;
							case 'partial':
								esc_html_e('No Partial Generations', 'ai-post-scheduler');
								break;
							default:
								esc_html_e('No Generated Posts', 'ai-post-scheduler');
								break;
						}
						?>
					</h3>
					<p class="aips-empty-state-description">
						<?php
						switch ($post_status_filter) {
							case 'published':
								esc_html_e('No published AI-generated posts found. Publish draft posts or set up schedules to generate content.', 'ai-post-scheduler');
								break;
							case 'pending_review':
								esc_html_e('There are no draft posts waiting for review. All generated posts have been published or deleted.', 'ai-post-scheduler');
								break;
							case 'partial':
								esc_html_e('Posts with missing generated components will appear here so you can review and repair them.', 'ai-post-scheduler');
								break;
							default:
								esc_html_e('No generated posts found. Start creating content by setting up templates and schedules.', 'ai-post-scheduler');
								break;
						}
						?>
					</p>
