			<!-- Close bulk-actions form for pending_review -->
			<?php if ($post_status_filter === 'pending_review' && !empty($posts_data)): ?>
			</form>
			<?php endif; ?>

			<!-- Table footer / pagination -->
			<div class="tablenav">
				<span class="aips-table-footer-count">
					<?php printf( esc_html( _n( '%s post', '%s posts', $unified['total'], 'ai-post-scheduler' ) ), number_format_i18n( $unified['total'] ) ); ?>
				</span>

				<?php if ($unified['pages'] > 1):
					$base_url = AIPS_Admin_Menu_Helper::get_page_url('generated_posts');
					$build_page_url = static function($page_number) use ($base_url, $author_id, $template_id, $search_query, $post_status_filter) {
						return add_query_arg(array_filter(array(
							'paged'              => absint($page_number),
							'author_id'          => $author_id ? $author_id : false,
							'template_id'        => $template_id ? $template_id : false,
							's'                  => $search_query ? $search_query : false,
							'post_status_filter' => $post_status_filter ? $post_status_filter : false,
						)), $base_url);
					};
					$start = max(1, $current_page - 3);
					$end   = min($unified['pages'], $current_page + 3);
				?>
				<div class="aips-history-pagination-links">
					<?php if ($current_page > 1): ?>
						<a class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-prev" href="<?php echo esc_url($build_page_url($current_page - 1)); ?>" aria-label="<?php esc_attr_e('Previous page', 'ai-post-scheduler'); ?>">
							<span class="dashicons dashicons-arrow-left-alt2"></span>
						</a>
					<?php else: ?>
						<button type="button" class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-prev" disabled aria-label="<?php esc_attr_e('Previous page', 'ai-post-scheduler'); ?>">
							<span class="dashicons dashicons-arrow-left-alt2"></span>
						</button>
					<?php endif; ?>

					<span class="aips-history-page-numbers">
						<?php if ($start > 1): ?>
							<a class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-link" href="<?php echo esc_url($build_page_url(1)); ?>">1</a>
							<?php if ($start > 2): ?><span class="aips-history-page-ellipsis">…</span><?php endif; ?>
						<?php endif; ?>

						<?php for ($p = $start; $p <= $end; $p++): ?>
							<?php if ($p === $current_page): ?>
								<span class="aips-btn aips-btn-sm aips-btn-primary" aria-current="page"><?php echo esc_html($p); ?></span>
							<?php else: ?>
								<a class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-link" href="<?php echo esc_url($build_page_url($p)); ?>"><?php echo esc_html($p); ?></a>
							<?php endif; ?>
						<?php endfor; ?>

						<?php if ($end < $unified['pages']): ?>
							<?php if ($end < $unified['pages'] - 1): ?><span class="aips-history-page-ellipsis">…</span><?php endif; ?>
							<a class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-link" href="<?php echo esc_url($build_page_url($unified['pages'])); ?>"><?php echo esc_html($unified['pages']); ?></a>
						<?php endif; ?>
					</span>

					<?php if ($current_page < $unified['pages']): ?>
						<a class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-next" href="<?php echo esc_url($build_page_url($current_page + 1)); ?>" aria-label="<?php esc_attr_e('Next page', 'ai-post-scheduler'); ?>">
							<span class="dashicons dashicons-arrow-right-alt2"></span>
						</a>
					<?php else: ?>
						<button type="button" class="aips-btn aips-btn-sm aips-btn-secondary aips-history-page-next" disabled aria-label="<?php esc_attr_e('Next page', 'ai-post-scheduler'); ?>">
							<span class="dashicons dashicons-arrow-right-alt2"></span>
						</button>
					<?php endif; ?>
				</div>
				<?php endif; ?>
			</div>
		</div><!-- .aips-content-panel -->
	</div>
</div>

